-- ============================================
-- Legislacao full-site: eduardo-girao / Senado / projetos_lei
-- Seed completo do recorte: autoria parlamentar substantiva Senado 2019-2026
-- ============================================
-- Fonte oficial: Senado Federal Dados Abertos
--   https://legis.senado.leg.br/dadosabertos/senador/5976/autorias.json
--   https://legis.senado.leg.br/dadosabertos/materia/{codigo}.json
--   https://legis.senado.leg.br/dadosabertos/materia/autoria/{codigo}.json
--   https://www25.senado.leg.br/web/atividade/materias/-/materia/{codigo}
--
-- Artefato de auditoria:
--   fonte interna de curadoria
--
-- Coverage:
--   coverage_id    = eduardo-girao-senado-completo-autoria-substantiva-2019-2026-20260506
--   coverage_scope = inventario_completo_senado_autoria_substantiva_2019_2026_20260506
--
-- Filtro factual: endpoint senador/5976/autorias.json com
--   IndicadorAutorPrincipal=Sim, siglas substantivas em
--   (PLS, PL, PEC, PLP, PRS, PDL, PDS, PCE), e endpoint
--   materia/autoria/{codigo}.json confirmando CodigoParlamentar=5976
--   com NumOrdemAutor=1. Resultado deste snapshot: 159 rows.
--
-- O recorte e completo apenas para a autoria parlamentar substantiva no Senado
-- retornada pelo endpoint oficial. Nao e inventario completo da vida publica do
-- candidato.
--
-- Esta migration NAO escreve em legislacao_mandato_executivo.
-- Esta migration NAO escreve em historico_politico.
-- Esta migration insere rows ausentes e atualiza coverage/metadata somente em
-- rows alvo Senado sem coverage_id divergente.
-- Esta migration NAO popula tema, destaque, destaque_motivo nem situacao
--   (campos editoriais/curatoriais, fora do contrato bruto de ingest oficial).
-- Esta migration NAO promove UI/whitelist publica; isso exige novo fechamento.
-- ============================================

DO $$
DECLARE
  cand_id uuid;
  projetos_total int;
  target_present int;
  target_count int;
  target_with_other_coverage int;
  mandato_senado_count int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'eduardo-girao';

  IF cand_id IS NULL THEN
    RAISE NOTICE 'eduardo-girao: candidato ausente neste banco local/CI minimo; seed projetos_lei Senado pulado';
    RETURN;
  END IF;

  SELECT count(*) INTO projetos_total
  FROM projetos_lei
  WHERE candidato_id = cand_id;

  SELECT count(*) INTO target_count
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND coverage_id = 'eduardo-girao-senado-completo-autoria-substantiva-2019-2026-20260506';

  SELECT count(*) INTO target_present
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND proposicao_id_api IN ('136752', '138740', '135119', '135122', '135290', '135943', '136175', '136355', '136581', '137212', '137482', '137483', '137900', '138069', '138215', '138414', '138585', '138698', '138890', '139313', '139862', '138021', '141929', '145023', '140489', '140602', '140627', '141513', '141529', '141558', '141584', '141840', '143907', '144735', '145039', '145285', '145410', '145442', '145683', '145760', '145081', '145150', '145212', '151136', '151176', '151174', '154465', '155568', '151792', '151847', '152021', '152041', '152073', '152412', '153543', '154211', '154464', '154490', '154565', '154814', '155502', '155576', '152513', '153486', '155000', '155750', '155751', '156183', '156782', '156962', '158859', '161725', '155903', '155914', '156329', '158619', '158620', '158621', '159504', '159509', '159680', '159773', '161067', '161389', '161390', '155863', '162281', '162876', '163436', '161898', '162431', '162938', '163047', '163174', '164010', '164011', '164215', '165080', '165206', '165251', '165604', '166149', '166150', '166151', '166172', '166251', '166483', '166498', '165766', '161937', '167054', '167122', '167239', '168266', '168615', '169814', '170993', '171884', '167250', '167795', '167868', '167898', '168265', '168267', '168268', '168685', '168731', '168733', '168734', '168881', '169270', '169318', '169450', '169521', '169852', '169943', '169944', '170018', '170184', '171218', '171376', '171499', '171541', '171701', '171727', '172061', '167285', '171407', '167072', '171494', '172722', '172760', '172826', '172947', '172685', '172833', '173512', '173755', '173756');

  SELECT count(*) INTO target_with_other_coverage
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND proposicao_id_api IN ('136752', '138740', '135119', '135122', '135290', '135943', '136175', '136355', '136581', '137212', '137482', '137483', '137900', '138069', '138215', '138414', '138585', '138698', '138890', '139313', '139862', '138021', '141929', '145023', '140489', '140602', '140627', '141513', '141529', '141558', '141584', '141840', '143907', '144735', '145039', '145285', '145410', '145442', '145683', '145760', '145081', '145150', '145212', '151136', '151176', '151174', '154465', '155568', '151792', '151847', '152021', '152041', '152073', '152412', '153543', '154211', '154464', '154490', '154565', '154814', '155502', '155576', '152513', '153486', '155000', '155750', '155751', '156183', '156782', '156962', '158859', '161725', '155903', '155914', '156329', '158619', '158620', '158621', '159504', '159509', '159680', '159773', '161067', '161389', '161390', '155863', '162281', '162876', '163436', '161898', '162431', '162938', '163047', '163174', '164010', '164011', '164215', '165080', '165206', '165251', '165604', '166149', '166150', '166151', '166172', '166251', '166483', '166498', '165766', '161937', '167054', '167122', '167239', '168266', '168615', '169814', '170993', '171884', '167250', '167795', '167868', '167898', '168265', '168267', '168268', '168685', '168731', '168733', '168734', '168881', '169270', '169318', '169450', '169521', '169852', '169943', '169944', '170018', '170184', '171218', '171376', '171499', '171541', '171701', '171727', '172061', '167285', '171407', '167072', '171494', '172722', '172760', '172826', '172947', '172685', '172833', '173512', '173755', '173756')
    AND coverage_id IS NOT NULL
    AND coverage_id <> 'eduardo-girao-senado-completo-autoria-substantiva-2019-2026-20260506';

  IF target_with_other_coverage <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao eduardo-girao: % rows alvo Senado ja tem coverage_id divergente', target_with_other_coverage;
  END IF;

  SELECT count(*) INTO mandato_senado_count
  FROM historico_politico hp
  WHERE hp.candidato_id = cand_id
    AND COALESCE(hp.tipo_evento, 'mandato') = 'mandato'
    AND (hp.cargo ILIKE '%Senador%' OR hp.cargo_canonico = 'Senador')
    AND UPPER(COALESCE(hp.estado, '')) = 'CE'
    AND COALESCE(hp.periodo_inicio, 9999) <= 2026
    AND COALESCE(hp.periodo_fim, 9999) >= 2019;

  IF mandato_senado_count < 1 THEN
    RAISE EXCEPTION 'Pre-condicao eduardo-girao: mandato Senado/CE 2019-2026 nao encontrado em historico_politico';
  END IF;
END $$;

