    ('PL', '600', 2023, 'Altera os arts. 29, 30 e 33 do Capítulo V da Lei nº 13.756, de 12 de dezembro de 2018, que trata da modalidade lotérica denominada apostas de quota fixa, para vedar a oferta de jogos não expressamente autorizados pela legislação por parte das empresas que a exploram; excluir do mercado empresas que aliciam atletas, árbitros e treinadores para o cometimento de fraudes; direcionar recursos para mitigar danos sociais e aprimorar a fiscalização e o controle dessa atividade; e estabelecer limites às suas ações de publicidade, propaganda e patrocínio.', 'Senado', '155914', 'https://www25.senado.leg.br/web/atividade/materias/-/materia/155914', 'eduardo-girao-senado-completo-autoria-substantiva-2019-2026-20260506', 'inventario_completo_senado_autoria_substantiva_2019_2026_20260506', '{"proposicao_id_api":"155914","descricao_identificacao":"PL 600/2023","data_apresentacao":"2023-02-17","casa":"SF","codigo_parlamentar_senado":5976,"indicador_autor_principal_endpoint_senador":"Sim","indicador_outros_autores_endpoint_senador":"Não","num_ordem_autor":1,"total_autores":1,"partido_autor_no_protocolo":"NOVO","uf_autor_no_protocolo":"CE","autor_nome":"Eduardo Girão","fonte":"Senado Federal Dados Abertos","autorias_endpoint":"https://legis.senado.leg.br/dadosabertos/senador/5976/autorias.json","autoria_endpoint":"https://legis.senado.leg.br/dadosabertos/materia/autoria/155914.json","detalhe_endpoint":"https://legis.senado.leg.br/dadosabertos/materia/155914.json","public_url":"https://www25.senado.leg.br/web/atividade/materias/-/materia/155914","coverage_id":"eduardo-girao-senado-completo-autoria-substantiva-2019-2026-20260506","coverage_scope":"inventario_completo_senado_autoria_substantiva_2019_2026_20260506","lote":"A","tabela_alvo":"projetos_lei","legislacao_mandato_executivo_mixed":false,"curation_batch_id":"eduardo-girao-senado-lote-a-20260506","snapshot_consulta_em":"2026-05-06T05:01:30.390Z"}'::jsonb),
