DO $$
DECLARE
  cand_id uuid;
  uncovered_year_count int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'eduardo-girao';

  IF cand_id IS NULL THEN
    RAISE NOTICE 'eduardo-girao: validacao de mandato Senado pulada porque candidato nao existe neste banco local/CI minimo';
    RETURN;
  END IF;

  SELECT count(DISTINCT seed.ano) INTO uncovered_year_count
  FROM _seed_eduardo_girao_senado_lote_a_projetos seed
  WHERE NOT EXISTS (
    SELECT 1
    FROM historico_politico hp
    WHERE hp.candidato_id = cand_id
      AND COALESCE(hp.tipo_evento, 'mandato') = 'mandato'
      AND (hp.cargo ILIKE '%Senador%' OR hp.cargo_canonico = 'Senador')
      AND UPPER(COALESCE(hp.estado, '')) = 'CE'
      AND COALESCE(hp.periodo_inicio, 9999) <= seed.ano
      AND COALESCE(hp.periodo_fim, 9999) >= seed.ano
  );

  IF uncovered_year_count <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao eduardo-girao: existem % anos de proposicoes Senado sem cobertura em mandato Senado/CE', uncovered_year_count;
  END IF;
END $$;

WITH target AS (
  SELECT c.id AS candidato_id
  FROM candidatos c
  WHERE c.slug = 'eduardo-girao'
)
INSERT INTO projetos_lei (
  candidato_id,
  tipo,
  numero,
  ano,
  ementa,
  fonte,
  proposicao_id_api,
  url_inteiro_teor,
  coverage_id,
  coverage_scope,
  metadata
)
SELECT
  target.candidato_id,
  seed.tipo,
  seed.numero,
  seed.ano,
  seed.ementa,
  seed.fonte,
  seed.proposicao_id_api,
  seed.url_inteiro_teor,
  seed.coverage_id,
  seed.coverage_scope,
  seed.metadata
FROM target
CROSS JOIN _seed_eduardo_girao_senado_lote_a_projetos AS seed
ON CONFLICT (candidato_id, proposicao_id_api) DO UPDATE SET
  tipo = EXCLUDED.tipo,
  numero = EXCLUDED.numero,
  ano = EXCLUDED.ano,
  ementa = EXCLUDED.ementa,
  fonte = EXCLUDED.fonte,
  url_inteiro_teor = EXCLUDED.url_inteiro_teor,
  coverage_id = EXCLUDED.coverage_id,
  coverage_scope = EXCLUDED.coverage_scope,
  metadata = COALESCE(projetos_lei.metadata, '{}'::jsonb) || EXCLUDED.metadata
WHERE projetos_lei.coverage_id IS NULL
   OR projetos_lei.coverage_id = EXCLUDED.coverage_id;

DO $$
DECLARE
  cand_id uuid;
  total_count int;
  target_count int;
  scope_count int;
  lme_count int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'eduardo-girao';

  IF cand_id IS NULL THEN
    RAISE NOTICE 'eduardo-girao: pos-condicao pulada porque candidato nao existe neste banco local/CI minimo';
    RETURN;
  END IF;

  SELECT count(*) INTO total_count
  FROM projetos_lei
  WHERE candidato_id = cand_id;

  SELECT count(*) INTO target_count
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND fonte = 'Senado'
    AND proposicao_id_api IN ('136752', '138740', '135119', '135122', '135290', '135943', '136175', '136355', '136581', '137212', '137482', '137483', '137900', '138069', '138215', '138414', '138585', '138698', '138890', '139313', '139862', '138021', '141929', '145023', '140489', '140602', '140627', '141513', '141529', '141558', '141584', '141840', '143907', '144735', '145039', '145285', '145410', '145442', '145683', '145760', '145081', '145150', '145212', '151136', '151176', '151174', '154465', '155568', '151792', '151847', '152021', '152041', '152073', '152412', '153543', '154211', '154464', '154490', '154565', '154814', '155502', '155576', '152513', '153486', '155000', '155750', '155751', '156183', '156782', '156962', '158859', '161725', '155903', '155914', '156329', '158619', '158620', '158621', '159504', '159509', '159680', '159773', '161067', '161389', '161390', '155863', '162281', '162876', '163436', '161898', '162431', '162938', '163047', '163174', '164010', '164011', '164215', '165080', '165206', '165251', '165604', '166149', '166150', '166151', '166172', '166251', '166483', '166498', '165766', '161937', '167054', '167122', '167239', '168266', '168615', '169814', '170993', '171884', '167250', '167795', '167868', '167898', '168265', '168267', '168268', '168685', '168731', '168733', '168734', '168881', '169270', '169318', '169450', '169521', '169852', '169943', '169944', '170018', '170184', '171218', '171376', '171499', '171541', '171701', '171727', '172061', '167285', '171407', '167072', '171494', '172722', '172760', '172826', '172947', '172685', '172833', '173512', '173755', '173756');

  SELECT count(*) INTO scope_count
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND coverage_id = 'eduardo-girao-senado-completo-autoria-substantiva-2019-2026-20260506'
    AND coverage_scope = 'inventario_completo_senado_autoria_substantiva_2019_2026_20260506';

  SELECT count(*) INTO lme_count
  FROM legislacao_mandato_executivo
  WHERE candidato_id = cand_id;

  IF target_count <> 159 THEN
    RAISE EXCEPTION 'Pos-apply eduardo-girao: esperadas 159 rows alvo Senado em projetos_lei, encontradas %', target_count;
  END IF;

  IF scope_count <> 159 THEN
    RAISE EXCEPTION 'Pos-apply eduardo-girao: esperadas 159 rows com coverage_id/scope alvo, encontradas %', scope_count;
  END IF;

  IF lme_count <> 0 THEN
    RAISE EXCEPTION 'Pos-apply eduardo-girao: legislacao_mandato_executivo deve permanecer 0, encontrado %', lme_count;
  END IF;

  RAISE NOTICE 'Pos-apply eduardo-girao Senado Lote A: projetos_lei=% coverage_scope=% legislacao_mandato_executivo=%', total_count, scope_count, lme_count;
END $$;
